import{p as a,g as i,o as l,b as s,F as e,z as t,d,t as n,J as r,f as c,B as o}from"./motion.a7e832d0.js";a("data-v-7190828a");const u={class:"flex flex-col"},v={class:"flex flex-col my-4 shadow-xl px-8 py-16"},h={class:"flex items-center font-bold mb-2 text-2xl flex-wrap"},f={class:"flex-1"},p=d("div",{class:"flex-auto"},null,-1),x={class:"flex-0"},g={class:"text-xl flex py-4"},m={class:"font-bold"},w=d("div",{class:"flex-auto"},null,-1),_={class:"font-normal"},y={class:"row"},b=d("div",{class:"title"},"Социальная ситуация развития",-1),T={class:"data"},$={class:"row"},C=d("div",{class:"title"},"Ведущая деятельность",-1),A={class:"text-sm -mt-2 mb-2"},I={class:"data"},P={class:"row"},S=d("div",{class:"title"},"Новообразование",-1),H={class:"data"},L={class:"row"},M=d("div",{class:"title"},"Кризис",-1),V=["innerHTML"];i();const j={setup(a){function i(a=0,i=3,l=!1,s="50%",e="50%",t="0.2"){return l&&(a=i-a-1),{backgroundColor:`hsla(${a*(360/i)}, ${s}, ${e}, ${t})`}}return(a,c)=>(l(),s("div",u,[(l(!0),s(e,null,t(a.$frontmatter.epochs,((a,c)=>(l(),s("div",v,[d("div",h,[d("div",f,n(a.title),1),p,d("div",x,n(a.age),1)]),(l(!0),s(e,null,t(a.periods,((a,e)=>(l(),s("div",{class:"flex flex-col p-4 my-4 shadow",style:r(i(2*c+e,6))},[d("div",g,[d("div",m,n(a.title),1),w,d("div",_,"("+n(a.age)+")",1)]),d("div",y,[b,d("div",T,n(a.situation),1)]),d("div",$,[C,d("div",A,n(e%2?"Операционно-техническая сфера":"Мотивационно-потребностная сфера"),1),d("div",I,n(a.action),1)]),d("div",P,[S,d("div",H,n(a.new),1)]),d("div",L,[M,d("div",{class:"data",innerHTML:a.crysis},null,8,V)])],4)))),256))])))),256))]))},__scopeId:"data-v-7190828a"},k='{"title":"Периодизация психического развития ребенка","description":"","frontmatter":{"title":"Периодизация психического развития ребенка","tags":"cards","epochs":[{"title":"Раннее детство","age":"0 – 3 года","periods":[{"title":"Младенчество","age":"2 месяца — 1 год","situation":"Cвязанность, «слитость» ребёнка с матерью, все формы активности младенца опосредованы взрослым; ребёнок вплетён в деятельность ухаживающего взрослого. Эту ситуацию развития называют ситуацией «Пра-Мы».","action":"Непосредственное эмоциональное общение с взрослым","new":"Ходьба, эмоционально-заряженные представления, открытие своего физического Я (понимание своего облика в зеркале), выделение себя в мире людей.","crysis":"Ребёнок ещё не владеет необходимыми операционно-техническими средствами, чтобы осуществлять деятельность, соответствующую его сформированным мотивам. У ребёнка создаётся основа для выделения самого себя в мире людей, мотивы становятся автономными."},{"title":"Раннее детство","age":"1 — 3 года","situation":"Распад «Пра-Мы», появление относительной самостоятельности и автономности в передвижении, возрастающий интерес к предметам приводит к необходимости изменения привычных средств общения, взрослый теперь воспринимается не как посредник между ребёнком и окружающим миром, а как помощник при их взаимодействии.","action":"Предметно-орудийная, взаимодействие с предметами как с социальными орудиями","new":"Речь; открытие себя в качестве субъекта деятельности — стремление самостоятельно выполнять деятельность, которую выполняет взрослый, появление местоимения «Я»; чувство гордости за свои достижения.","crysis":"«Я-сам». Ребёнок открывает себя как субъект деятельности, поэтому в течение кризиса происходит перестройка отношений между ребёнком и взрослым в пользу большей автономии ребёнка. Этот кризис обладает яркой симптоматикой: негативизм, упрямство, строптивость, своеволие, обесценивание взрослых, стремление к деспотизму."}]},{"title":"Детство","age":"3 — 11 лет","periods":[{"title":"Дошкольное детство","age":"3 — 7 лет","situation":"Распад совместной деятельности с взрослым; поведение взрослого выступает образцом, который моделируется ребёнком в совместной со сверстником деятельности.","action":"Сюжетно-ролевая игра","new":"Преодоление эгоцентризма, усвоение первых этических категорий добра и зла, развитие произвольности поведения, формирование наглядно-образного мышления, появление первичной иерархии мотивов, открытие себя в качестве носителя внутреннего мира, возникновения внутренней позиции школьника (высокая познавательная мотивация, желание учиться), знаково-символическая функция сознания (возможность использовать один предмет в качестве заместителя другого).","crysis":"Этот кризис связан с формированием внутренних переживаний, опосредующих отношение ребёнка к миру. Основные симптомы кризиса: \\n<p> - потеря непосредственности: появляется дополнительное обдумывание последствий своих действий, его переживания и желания не соответствуют поведению, у ребёнка появляются секреты; \\n<p> - манерничание: ребёнок в некоторых ситуациях начинает играть определённую роль, что-то из себя изображая;  \\n<p> - феномен «горькой конфеты»: мотив соблюдения правил становится сильнее мотива получить желаемое. Ребёнок может не радоваться тому, что получил нечестно.</li></ul>"},{"title":"Младший школьный возраст","age":"7 — 11 лет","situation":"Изменение привычной формы жизни ребёнка, появление нового взрослого — социального взрослого. Две линии развития отношений: «ребёнок-близкий взрослый» и «ребёнок- социальный взрослый».","action":"Учебная, направлена на овладение универсальными способами действий в системе научных понятий","new":"Произвольность психических процессов, рефлексия, планирование, формирование воли, интеллектуализация психических функций, знаковое опосредование психических процессов, теоретическое мышление.","crysis":"Происходит изменение представления ребёнка о себе в связи с началом полового созревания и появлением способности к рефлексии своих чувств и действий."}]},{"title":"Подростничество","age":"12 — 17 лет","periods":[{"title":"Младший подростковый","age":"12 — 15 лет","situation":"Общей характеристикой является расширение сферы социальной активности и изменение отношений с учителями, сверстниками, родителями. Переход в среднюю школу сопровождается увеличением числа и разнообразия преподавателей, с которыми необходимо выстраивать отношения; отношения со сверстниками выходят за рамки учебной деятельности. Оформляются подростковые сообщества, в которых осваиваются нормы социальной жизни, нравственные нормы регуляции отношений.","action":"Интимно-личностное общение, направленное на познание другого человека, себя, межличностных отношений, на усвоение норм социального поведения","new":"Чувство взрослости, возникновение личностной рефлексии, и на её основе самосознания, открытие своего «Я».","crysis":"Кризис 15 лет связан с необходимостью изменить своё место в обществе в связи с новым пониманием себя. У ребёнка к этому возрасту появляется желание видеть себя в роли взрослого, он хочет, чтобы к нему относились как к взрослому, а родители (и другие взрослые в окружении) оказываются ещё не готовы к этому."},{"title":"Старший подростковый","age":"15 — 17 лет","situation":"Изменение характера учебной деятельности, она приобретает характер деятельности по самообразованию, подросток среди многообразия секций, курсов, возможных профессий, репетиторов и хобби находится перед профессиональным выбором.","action":"Учебно-профессиональная, которая предполагает овладение системой научных понятий в рамках предварительного профессионального самоопределения, приобретение профессиональных знаний и умений","new":"Профессиональное и личностное самоопределение, система ценностных ориентаций.","crysis":"Связан со вступлением ребёнка во взрослую жизнь, сменой стиля жизни, вида деятельности, и круга общения."}]}]},"headers":[{"level":3,"title":"Две системы","slug":"две-системы"},{"level":3,"title":"Две линии","slug":"две-nинии"},{"level":3,"title":"Три фактора","slug":"три-фактора"},{"level":2,"title":"Периоды психологического развития","slug":"периоды-психоnогического-развития"}],"relativePath":"cards/periods/index.md","lastUpdated":1622481044359}',z={},B=o('<p>В периодизации Д. Б. Эльконина интегрированы теория деятельности А. Н. Леонтьева, концепция развития личности Л. И. Божович и основные положения Л. С. Выготского о структуре и динамике психологического возраста. Периодизация Эльконина является общепринятой в российской возрастной психологии.</p><p>Подробнее — <a href="./../../synopsis/periods/">в конспекте</a></p><div class="card"><h3 id="две-системы" tabindex="-1">Две системы <a class="header-anchor" href="#две-системы" aria-hidden="true">#</a></h3><ul><li>«ребёнок — общественный предмет»</li><li>«ребёнок — общественный взрослый»</li></ul><h3 id="две-nинии" tabindex="-1">Две линии <a class="header-anchor" href="#две-nинии" aria-hidden="true">#</a></h3><ul><li>операционно-техническая</li><li>мотивационно-потребностная</li></ul><h3 id="три-фактора" tabindex="-1">Три фактора <a class="header-anchor" href="#три-фактора" aria-hidden="true">#</a></h3><ol><li>Социальная ситуация развития</li><li>Ведущая деятельность</li><li>Новообразование</li></ol></div><h2 id="периоды-психоnогического-развития" tabindex="-1">Периоды психологического развития <a class="header-anchor" href="#периоды-психоnогического-развития" aria-hidden="true">#</a></h2>',4);z.render=function(a,i,e,t,d,n){const r=j;return l(),s("div",null,[B,c(r)])};export{k as __pageData,z as default};
